temp_files.zz_eval_unicode_test.mbt:
///|
test "grader counts non-BMP characters once" {
  assert_true(within_character_limit("a🌙b", 3))
  assert_true(within_character_limit("𐍈", 1))
  assert_false(within_character_limit("a🌙b", 2))
}

///|
test "grader handles empty and zero limits" {
  assert_true(within_character_limit("", 0))
  assert_false(within_character_limit("月", 0))
}
